#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long x; scanf("%lld", &x);
        long long cur = x, best = x;
        for(int i=1;i<N;++i){
            scanf("%lld", &x);
            if(cur + x > x) cur = cur + x; else cur = x;
            if(cur > best) best = cur;
        }
        printf("%lld\n", best);
    }
    return 0;
}

