#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        long long x; cin>>x;
        long long cur=x, best=x;
        for(int i=1;i<N;++i){
            cin>>x;
            cur = max(x, cur + x);
            best = max(best, cur);
        }
        cout<<best<<"\n";
    }
    return 0;
}

